// src/components/DirectoryPane.jsx
import React from "react";

export default function DirectoryPane({ users }) {
  return (
    <div className="w-64 bg-white border-l p-4 overflow-y-auto">
      <h3 className="text-lg font-semibold mb-3 text-blue-600">Users</h3>
